/* empty css     */document.addEventListener("DOMContentLoaded",()=>{const a=document.querySelector(".clesk-header--transparent");if(a){const e=()=>{a.classList.toggle("clesk-header--scrolled",window.scrollY>50)};window.addEventListener("scroll",e,{passive:!0}),e()}if(document.querySelectorAll(".clesk-video-play-btn").forEach(o=>{o.addEventListener("click",()=>{const e=o.dataset.videoUrl;if(!e)return;let n=e;const r=e.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([\w-]+)/);r&&(n=`https://www.youtube-nocookie.com/embed/${r[1]}?autoplay=1`);const c=e.match(/vimeo\.com\/(\d+)/);c&&(n=`https://player.vimeo.com/video/${c[1]}?autoplay=1`);const t=document.createElement("div");t.className="clesk-video-modal",t.innerHTML=`<iframe src="${n}" allow="autoplay; fullscreen" allowfullscreen></iframe>`,t.addEventListener("click",s=>{s.target===t&&t.remove()}),document.body.appendChild(t);const l=s=>{s.key==="Escape"&&(t.remove(),document.removeEventListener("keydown",l))};document.addEventListener("keydown",l)})}),document.querySelectorAll('a[href*="#"]').forEach(o=>{o.addEventListener("click",e=>{const n=o.getAttribute("href"),r=n.indexOf("#");if(r===-1)return;const c=n.substring(r+1);if(!c)return;const t=new URL(n,window.location.href);if(t.pathname!==window.location.pathname&&t.origin===window.location.origin)return;const l=document.getElementById(c);l&&(e.preventDefault(),l.scrollIntoView({behavior:"smooth",block:"start"}),history.pushState(null,null,"#"+c))})}),window.location.hash){const o=window.location.hash.substring(1),e=document.getElementById(o);e&&setTimeout(()=>{e.scrollIntoView({behavior:"smooth",block:"start"})},100)}});
